import { Component, OnInit } from '@angular/core';
import { FormBuilder, FormGroup, Validators, ReactiveFormsModule } from '@angular/forms';
import { DecimalPipe } from '@angular/common';
import { ProductService } from '../../../core/services/product.service';
import { Product } from '../../../core/models/product.model';

@Component({
  selector: 'app-admin-products',
  standalone: true,
  imports: [ReactiveFormsModule, DecimalPipe],
  styleUrl: './admin-products.component.scss',
  template: `
    <div class="admin-products">
      <div class="page-header">
        <h1>Products</h1>
        <button class="btn-primary" (click)="openForm()">+ Add Product</button>
      </div>

      @if (showForm) {
        <div class="form-panel">
          <h2>{{ editingId ? 'Edit Product' : 'New Product' }}</h2>
          <form [formGroup]="form" (ngSubmit)="saveProduct()">
            <div class="form-grid">
              <div class="field full">
                <label>Name *</label>
                <input type="text" formControlName="name" placeholder="Product name" />
              </div>
              <div class="field">
                <label>Price (TND) *</label>
                <input type="number" formControlName="price" placeholder="0.00" step="0.01" />
              </div>
              <div class="field">
                <label>Material</label>
                <input type="text" formControlName="material" placeholder="100% Cotton" />
              </div>
              <div class="field full">
                <label>Description</label>
                <textarea formControlName="description" rows="3" placeholder="Product description..."></textarea>
              </div>
              <div class="field full">
                <label>Story</label>
                <textarea formControlName="story" rows="2" placeholder="The story behind this piece..."></textarea>
              </div>
              <div class="field full">
                <label>Image URLs <span class="hint">(one per line)</span></label>
                <textarea formControlName="imageUrlsText" rows="3" placeholder="https://example.com/image1.jpg"></textarea>
              </div>
              <div class="field full">
                <label>Available Sizes <span class="hint">(comma-separated: XS, S, M, L, XL)</span></label>
                <input type="text" formControlName="sizesText" placeholder="XS, S, M, L, XL" />
              </div>
              <div class="field">
                <label>Weight</label>
                <input type="text" formControlName="weight" placeholder="350g" />
              </div>
              <div class="field toggles">
                <label class="toggle">
                  <input type="checkbox" formControlName="inStock" />
                  <span>In Stock</span>
                </label>
                <label class="toggle">
                  <input type="checkbox" formControlName="featured" />
                  <span>Featured</span>
                </label>
              </div>
            </div>
            @if (formError) { <p class="form-error">{{ formError }}</p> }
            <div class="form-actions">
              <button type="button" class="btn-outline" (click)="cancelForm()">Cancel</button>
              <button type="submit" class="btn-primary" [disabled]="saving">
                {{ saving ? 'Saving...' : (editingId ? 'Update' : 'Create') }}
              </button>
            </div>
          </form>
        </div>
      }

      @if (loading) {
        <p class="loading-text">Loading products...</p>
      } @else if (products.length === 0) {
        <p class="empty-text">No products yet. Add your first product above.</p>
      } @else {
        <div class="table-wrapper">
          <table class="data-table">
            <thead>
              <tr>
                <th>#</th>
                <th>Image</th>
                <th>Name</th>
                <th>Price</th>
                <th>Sizes</th>
                <th>Stock</th>
                <th>Featured</th>
                <th>Actions</th>
              </tr>
            </thead>
            <tbody>
              @for (product of products; track product.id) {
                <tr>
                  <td>{{ product.id }}</td>
                  <td>
                    <div class="thumb">
                      @if (product.imageUrls?.length) {
                        <img [src]="product.imageUrls[0]" [alt]="product.name" />
                      } @else {
                        <div class="thumb-placeholder">{{ product.name[0] }}</div>
                      }
                    </div>
                  </td>
                  <td class="product-name">{{ product.name }}</td>
                  <td>{{ product.price | number:'1.2-2' }} TND</td>
                  <td class="sizes-cell">{{ product.availableSizes?.join(', ') || '—' }}</td>
                  <td>
                    <span class="pill" [class.yes]="product.inStock" [class.no]="!product.inStock">
                      {{ product.inStock ? 'In Stock' : 'Out' }}
                    </span>
                  </td>
                  <td>
                    <span class="pill" [class.yes]="product.featured">
                      {{ product.featured ? 'Yes' : 'No' }}
                    </span>
                  </td>
                  <td class="action-cell">
                    <button class="action-btn edit" (click)="editProduct(product)">Edit</button>
                    <button class="action-btn delete" (click)="deleteProduct(product.id)">Delete</button>
                  </td>
                </tr>
              }
            </tbody>
          </table>
        </div>
      }
    </div>
  `
})
export class AdminProductsComponent implements OnInit {
  products: Product[] = [];
  loading = true;
  showForm = false;
  editingId: number | null = null;
  saving = false;
  formError = '';
  form: FormGroup;

  constructor(private productService: ProductService, private fb: FormBuilder) {
    this.form = this.fb.group({
      name: ['', Validators.required],
      price: [null, [Validators.required, Validators.min(0)]],
      description: [''],
      story: [''],
      material: [''],
      weight: [''],
      sizesText: [''],
      imageUrlsText: [''],
      inStock: [true],
      featured: [false]
    });
  }

  ngOnInit(): void {
    this.loadProducts();
  }

  loadProducts(): void {
    this.loading = true;
    this.productService.getAll().subscribe({
      next: (p) => { this.products = p; this.loading = false; },
      error: () => { this.loading = false; }
    });
  }

  openForm(): void {
    this.editingId = null;
    this.form.reset({ inStock: true, featured: false });
    this.showForm = true;
    this.formError = '';
  }

  editProduct(product: Product): void {
    this.editingId = product.id;
    this.form.patchValue({
      name: product.name,
      price: product.price,
      description: product.description,
      story: product.story,
      material: product.material,
      weight: product.weight,
      sizesText: product.availableSizes?.join(', ') ?? '',
      imageUrlsText: product.imageUrls?.join('\n') ?? '',
      inStock: product.inStock,
      featured: product.featured
    });
    this.showForm = true;
    this.formError = '';
  }

  cancelForm(): void {
    this.showForm = false;
    this.editingId = null;
  }

  saveProduct(): void {
    if (this.form.invalid) return;
    this.saving = true;
    this.formError = '';
    const v = this.form.value;
    const payload: Partial<Product> = {
      name: v.name,
      price: v.price,
      description: v.description,
      story: v.story,
      material: v.material,
      weight: v.weight,
      availableSizes: v.sizesText ? v.sizesText.split(',').map((s: string) => s.trim()).filter(Boolean) : [],
      imageUrls: v.imageUrlsText ? v.imageUrlsText.split('\n').map((s: string) => s.trim()).filter(Boolean) : [],
      inStock: v.inStock,
      featured: v.featured
    };

    const req = this.editingId
      ? this.productService.update(this.editingId, payload)
      : this.productService.create(payload);

    req.subscribe({
      next: () => { this.loadProducts(); this.cancelForm(); this.saving = false; },
      error: () => { this.formError = 'Save failed. Check your credentials and try again.'; this.saving = false; }
    });
  }

  deleteProduct(id: number): void {
    if (!confirm('Delete this product?')) return;
    this.productService.delete(id).subscribe({
      next: () => { this.products = this.products.filter(p => p.id !== id); },
      error: () => alert('Delete failed.')
    });
  }
}
